// Particle Flow Field
// Adapted from GenerativeArtGallery / artwork1

let flowPts = [];
let flowPrevMode = null;

p.setup = function() {
  p.createCanvas(400, 400);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  p.frameRate(30);
  for (let i = 0; i < 400; i++) {
    flowPts.push({
      x: p.random(p.width), y: p.random(p.height),
      px: 0, py: 0, vx: 0, vy: 0,
      hue: p.random(360), spd: p.random(1.5, 3)
    });
  }
  flowPts.forEach(function(pt) { pt.px = pt.x; pt.py = pt.y; });
};

p.draw = function() {
  let modeStr = p.getSynthVar('flow_mode') || 'perlin';
  let palStr = p.getSynthVar('color_palette') || 'angle';
  let trailStr = p.getSynthVar('trail_mode') || 'medium';
  let densityStr = p.getSynthVar('particle_density') || 'medium';
  let speedStr = p.getSynthVar('flow_speed') || 'medium';

  if (modeStr !== flowPrevMode) {
    flowPts.forEach(function(pt) {
      pt.x = p.random(p.width); pt.y = p.random(p.height);
      pt.px = pt.x; pt.py = pt.y; pt.vx = 0; pt.vy = 0;
    });
    flowPrevMode = modeStr;
  }

  let bgAlpha = trailStr === 'sharp' ? 100 : trailStr === 'medium' ? 18 : trailStr === 'ghostly' ? 6 : 2;
  let spdMult = speedStr === 'slow' ? 0.6 : speedStr === 'medium' ? 1 : 2;
  let numPts = densityStr === 'sparse' ? 80 : densityStr === 'medium' ? 220 : 400;

  p.background(240, 15, 8, bgAlpha);

  let t = p.frameCount * 0.005;
  let cx = p.width / 2, cy = p.height / 2;

  for (let i = 0; i < numPts; i++) {
    let pt = flowPts[i];
    pt.px = pt.x; pt.py = pt.y;
    let dx = pt.x - cx, dy = pt.y - cy;
    let angle;

    if (modeStr === 'perlin') {
      angle = p.noise(pt.x * 0.005, pt.y * 0.005, t) * p.TWO_PI * 4;
    } else if (modeStr === 'circular') {
      angle = p.atan2(dy, dx) + p.HALF_PI;
    } else if (modeStr === 'gravity') {
      angle = p.atan2(-dy, -dx);
    } else if (modeStr === 'wave') {
      angle = p.sin(pt.x * 0.02 + t * 2) * p.PI;
    } else if (modeStr === 'chaos') {
      angle = p.noise(pt.x * 0.012, pt.y * 0.012, t * 1.5) * p.TWO_PI * 8;
    } else {
      angle = p.noise(pt.x * 0.005, pt.y * 0.005, t) * p.TWO_PI * 4;
    }

    let force = 0.35 * spdMult;
    pt.vx = pt.vx * 0.88 + p.cos(angle) * force;
    pt.vy = pt.vy * 0.88 + p.sin(angle) * force;

    let spd = p.sqrt(pt.vx * pt.vx + pt.vy * pt.vy);
    if (spd > pt.spd * spdMult) {
      pt.vx = pt.vx / spd * pt.spd * spdMult;
      pt.vy = pt.vy / spd * pt.spd * spdMult;
    }

    pt.x += pt.vx; pt.y += pt.vy;

    if (pt.x < 0) { pt.x = p.width; pt.px = p.width; }
    if (pt.x > p.width) { pt.x = 0; pt.px = 0; }
    if (pt.y < 0) { pt.y = p.height; pt.py = p.height; }
    if (pt.y > p.height) { pt.y = 0; pt.py = 0; }

    let hue;
    if (palStr === 'fire') hue = p.map(p.noise(pt.x * 0.01, pt.y * 0.01, t), 0, 1, 0, 55);
    else if (palStr === 'ocean') hue = p.map(p.noise(pt.x * 0.01, pt.y * 0.01, t), 0, 1, 180, 240);
    else if (palStr === 'forest') hue = p.map(p.noise(pt.x * 0.01, pt.y * 0.01, t), 0, 1, 85, 145);
    else if (palStr === 'neon') { pt.hue = (pt.hue + 0.3) % 360; hue = pt.hue; }
    else hue = ((angle / p.TWO_PI + 1) * 360) % 360;

    p.stroke(hue, 85, 90, 75);
    p.strokeWeight(1.2);
    p.line(pt.px, pt.py, pt.x, pt.y);
  }
};
